mapper.update:
UPDATE `purchase`
bill_no = #{billNo}, supplier_id = #{supplierId}, warehouse_id = #{warehouseId}, total_amount = #{totalAmount}, status = #{status}, in_stock_time = #{inStockTime}, remark = #{remark}, confirm_time = #{confirmTime}, update_time = NOW(),
WHERE id = #{id}

mapper.select:
SELECT p.*, s.name AS supplier_name FROM `purchase` p LEFT JOIN supplier s ON p.supplier_id = s.id
AND p.bill_no LIKE CONCAT('%', #{billNo}, '%') AND p.supplier_id = #{supplierId} AND p.status = #{status}
ORDER BY p.id DESC
